logic.pre_loop:
// Initialise once

    gErrorDir = pErrorsDir;
    gLookupDir = pLookupsDir;
    gOutputRCP = GetRCPStatus(pErrorData);
    gInitialised = CreateMemoryMapping();
    CreateKeyTable();

    gNrbOfLoops = 0;
    gPcsIdSearch = "";
    gPcsIdParam = pPcsId;
    gSrcIdParam = pSrcId;
    gRunIdParam = pRunId;
    gPcsIdSearch = "";
    gSrcIdSearch = "";
    gRunIdSearch = "";

// Construct the Job audit data and file name from DataStage 'macros' (passed in a 'parameters', or arguments here)

   gJobInfo  = DQuote(pHostName);
   gJobInfo += "," + DQuote(pProjectName);
   gJobInfo += "," + DQuote(pJobController);
   gJobInfo += "," + DQuote(pJobName);
   gJobInfo += "," + DQuote(pJobInvocationId);
   gJobInfo += "," + DQuote(pJobStartTimestamp);

   gJobStartTimestamp = Convert(" :-", "", pJobStartTimestamp);

   gFileName = pRunId + "." + pHostName + "." + pProjectName + "." + pJobName + "." + pJobInvocationId + "." + pSrcId + "." + gJobStartTimestamp;

   gCurName  = gErrorDir + "/" + gFileName + ".tmp";
   gNewName  = gErrorDir + "/" + gFileName + ".err";

// Open the error log file using the file name constructed above
// Note. The failstep on failure to open will abort the job
 
   gLogHandle = fopen(gErrorDir + "/" + gFileName + ".tmp", "a");
   if ( ! gLogHandle ) {
      fprintf(stderr, "Unable to open log file (%s/%s.tmp)\n", gErrorDir.data(), gFileName.data());
      failStep();
   }

// If we failed initialisation, log it as an error

   if ( gInitialised < 0 ) {
       gErrorCode = "DS_ERR_0";
       gErrorSeverity = "1";
       gErrorData  = DQuote("ERROR");
       gErrorData += "," + DQuote("FAILED");
       gErrorData += "," + DQuote("Initialisation failure mapping errors file");
       LogIt(gNrbOfLoops, pNbrOfWarnToLog);
       failStep();
   }

logic.post_loop:
// Close the file

   if ( gLogHandle )
      fclose(gLogHandle);

// Delete the file

   if ( gNrbOfLoops == 0 )
      {
      iResult = remove(gCurName);

      if ( iResult == 0 )
         {
         fprintf(stdout, "Log file (%s) has been deleted\n", gCurName.data());
         }
      else
         {
         fprintf(stderr, "Unable to delete log file (%s)\n", gCurName.data());
         failStep();
         }
      }
   else
      {

      // Rename the file

      iResult = rename(gCurName, gNewName);

      if ( iResult == 0 )
         {
         fprintf(stdout, "Log file (%s) has been renamed\n", gCurName.data());
         }
      else
         {
         fprintf(stderr, "Unable to rename log file (%s)\n", gCurName.data());
         failStep();
         }

      // If we have a severity 1 error, the job must fail
      // If severity is 1 all erroneous records are first written to a file and then a job fails

      if ( gErrorSeverity == "1" ) {
         fprintf(stderr,"Severity 1 error (%s) encountered (%s). Aborting Job.\n", gErrorCode.data(), gErrorData.data());
         failStep();
         }
      }

logic.definitions:
// Include files

    #include <stdio.h>
    #include <unistd.h>
    #include <sys/mman.h>
    #include <fcntl.h>
    #include <sys/stat.h>
    #include <sys/types.h>
    #include <map>
    #include <apt_framework/tfmop_functions.h>
    #include <apt_util/time.h>

    using namespace std;

// Expose the functions as BASIC function names

    #define Dcount(aString, aDelim)              APT_TOFunctions::get().dcount_substring(aString, aDelim);
    #define Trim(aString)                        APT_TOFunctions::get().trimc_string(aString);
    #define Field(aString,aDelim,aInstance)      APT_TOFunctions::get().substring_by_delimiter(aString, aDelim, aInstance);
    #define Fields(aString,aDelim,aStart,aCount) APT_TOFunctions::get().substring_by_delimiter(aString, aDelim,aStart,aCount);
    #define Convert(aReplace, aWith, aInString)  APT_TOFunctions::get().replace_substring(aReplace, aWith, aInString);
    #define DQuote(aString)                      APT_TOFunctions::get().double_quote_string(aString);
    #define UstringToString(auString)            APT_TOFunctions::get().string_from_ustring(auString);
    #define CurrentTimeStamp()                   APT_TimeStamp::localTimeStamp().asString("%yyyy-%mm-%dd %hh:%nn:%ss");

// Global variable declarations

    APT_String gErrorSeverity;  // Global variable referencing the Error Severity within ErrorData
    APT_String gErrorData;      // Global variable referencing looked-up Error Data. used in the output Log

    FILE *gLogHandle;           // A handle for the file stream, opened against FileName(see below) 
    APT_String gLogData;        // A string containing the pipe ('|') delimited log data (See Interfaces 'Output')

    int gNrbOfLoops;            // Number of warnings to be written to a log

// Input Data

    APT_String gInData;          // Used to convert from ustring (Source data) because the peek stage insists on ustring

// Input data 'columns'

    APT_String gErrorCode;      // The Error Code from the Errors.nsv file
    APT_String gAdditionalInfo; // Additional (context) information provided by the developer
    APT_String gRCPData = "";   // The run-time propogated data from the primary input link and/or output links of the Stage raising the exception

// PcsId related

    APT_String gPcsId;          // The PcsId which will be computed as pscErrorPcsId or else from the pPcsId parameter
    APT_String gPcsIdParam;     // The PcsId parameter passed in as a property
    APT_String gPcsIdSearch;    // To hold the search string containing ' ||PcsIdColumn:' that will be used to locate the PcsId from the input data

// SrcId related

    APT_String gSrcId;          // The SrcId which will be computed as pscErrorSrcId or else from the pSrcId parameter
    APT_String gSrcIdParam;     // The SrcId parameter passed in as a property
    APT_String gSrcIdSearch;    // To hold the search string containing ' ||RunSrcIdColumn:' that will be used to locate the RunSrcId from the input data

// RunId related

    APT_String gRunId;          // The RunId which will be computed as pscErrorRunId or else from the pRunId parameter
    APT_String gRunIdParam;     // The RunId parameter passed in as a property
    APT_String gRunIdSearch;    // To hold the search string containing ' ||RunIdColumn:' that will be used to locate the RunId from the input data

// Log file

    APT_String gFileName;      // For opening/creating a filename in append mode. Same as JobInfo, but with '.' delimiters.

// Log data

    APT_String gJobInfo;       // For recording the constant Job 'macro' informationthat is output to the log ('|' delimited)
    APT_String gNow;           // For recording the variable timestamp at this point in time
    APT_String gJobStartTimestamp; // Cleaned value of the pJobStartTimestamp property

// File names

    APT_String gLookupDir;     // Error list file location and name
    APT_String gErrorDir;      // Error log file location and name

// Rename file

   int iResult;
   APT_String gCurName;
   APT_String gNewName;

// Environment Variables

    APT_String gRCPDataEnv     = getenv("ERROR_DATA");

// RCP Output control

    APT_Int8 gOutputRCP;       // Controls whether RCP data capture is required

// Comparison function for the map class functions that find matches and insert elements

    struct KeyLess { bool operator() (const APT_String s,const APT_String t) 
                      const { return s < t; } };

// Type definitions - to simplify things elsewhere

    struct gErrorStruct { 
       APT_String ErrorCode;
       APT_String ErrorSeverity;
       APT_String ErrorData;
    };
    typedef map <APT_String, gErrorStruct, KeyLess> KM;
    typedef KM::iterator KMI;
    typedef pair<KMI,KMI> KP;

// Global static variables (retained bwetween calls)

     static KM    gKeyMap;
     static KMI   gKeyMapI;

     static KP    gKeyPair;
     static char *gData;
     static int   gInitialised = 0;

// Mapping characters

    APT_String gMapIn  = "\x0A\x1B\x22\x2C";
    APT_String gMapOut = "\x20\x20\xF9\xFA";

// Create a memory map to the Scheme/Classification extract file

     int CreateMemoryMapping() {
        int FV;
        struct stat FileInfo;

        if ( gLookupDir == "" ) {
           fprintf(stderr, "Errors lookup file directory is missing\n");
           return -1;
           }

        gLookupDir += "/errors.nsv";

        if ( (FV = open(gLookupDir.data(),O_RDONLY)) == -1 ) {
           fprintf(stderr, "open(): Errors file errors.nsv is missing\n");
           return -2;
           }

        if ( fstat(FV,&FileInfo) == -1 ) {
           fprintf(stderr, "fstat(): Errors file errors.nsv is missing\n");
           return -3;
           }

        if ( ! FileInfo.st_size ) {
           fprintf(stderr, "Errors file errors.nsv is empty\n");
           return -4;
           }

        gData = (caddr_t) mmap(0, FileInfo.st_size, PROT_READ, MAP_SHARED, FV, 0);

        if ( gData == (caddr_t) -1 ) {
           fprintf(stderr, "Can not read errors file errors.nsv\n");
           return -5;
           }

        close(FV);
        return 0;
     }

// Create a Key-Data in-memory table pointing to the contents of the 
// memory-mapped file. Note, that we are talking POINTERS here, not
// copies of the data.

     void CreateKeyTable() {
        char *pKey;
        char *pData;

        for ( pKey = gData ; strcmp(pKey,"EOF."); pKey = strchr(pData,'\0') + 1 ) {
           gKeyMap[pKey].ErrorCode = pKey;
           pData = strchr(pKey,'\0') + 1;
           gKeyMap[pKey].ErrorSeverity = pData;
           pData = strchr(pData, '\0') + 1;
           gKeyMap[pKey].ErrorData = pData;
        }
     }

// Determine if RCP data is to be output

     APT_Int8 GetRCPStatus(APT_String aErrorData) {
        APT_String ErrorData;

        if ( aErrorData == "" )
           ErrorData = gRCPDataEnv;
        else
           ErrorData = aErrorData;
        return ( toupper(*(ErrorData.data())) != 'N');
     }

/// Seek out the PcsId if possible and/or necessary

     void GetPcsId() {
        gPcsId = gPcsIdParam;
        return;
    }

// Seek out the SrcId if possible and/or necessary

     void GetSrcId() {
        gSrcId = gSrcIdParam;
        return;
    }

// Seek out the RunId if possible and/or necessary

     void GetRunId() {
        gRunId = gRunIdParam;
        return;
    }

// Get Error reference data for ErrorCode  - create a severity 1 error if not found (will abort the Job)

     void GetErrorKey(APT_String aErrorId) {
        if ( aErrorId == "" ) {
           gErrorCode     = "DS_ERR_0";
           gErrorSeverity = "1";
           gErrorData     = DQuote("ERROR");
           gErrorData    += "," + DQuote("UNKNOWN");
           gErrorData    += "," + DQuote("Empty error code requested");
           return;
        }

        gKeyMapI = gKeyMap.find(aErrorId);

        if ( gKeyMapI == gKeyMap.end() ) {
           gErrorCode     = "DS_ERR_0";
           gErrorSeverity = "1";
           gErrorData     = DQuote("ERROR");
           gErrorData    += "," + DQuote("UNKNOWN");
           gErrorData    += "," + DQuote("Unknown error [" + aErrorId + "]");
           return;
        }

        gErrorSeverity = (*gKeyMapI).second.ErrorSeverity;
        gErrorData     = (*gKeyMapI).second.ErrorData;
     }

// Log the error

     APT_Status LogIt(int gNrbOfLoops, int pNbrOfWarnToLog) {

   // Get the current time

        gNow = CurrentTimeStamp();

   // Construct the error log record

        gLogData  = DQuote(gErrorCode);
        gLogData += "," + DQuote(gAdditionalInfo);
        gLogData += "," + DQuote(gSrcId);
        gLogData += "," + DQuote(gPcsId);
        gLogData += "," + DQuote(gRunId);
        gLogData += "," + DQuote(gErrorSeverity);
        gLogData += "," + gErrorData;
        gLogData += "," + DQuote(gNow);
        gLogData += "," + gJobInfo;
        gLogData += "," + DQuote(gRCPData);
        gLogData += "\n";

   // ... and write it away with immediate flush (remember it is opened in append mode so no need to seek to end)

        fwrite(gLogData.data(), 1, gLogData.length(), gLogHandle);
        fflush(gLogHandle);

   // Now write to a data stage log if needed. 
   // If pNbrOfWarnToLog is 0 then do not log any warnings if it is set to -1 log all. Otherwise write number of warnings specified.

        if ( gNrbOfLoops <= pNbrOfWarnToLog) {
           fprintf(stderr, "%s\n", gLogData.data());
        }
        else if (pNbrOfWarnToLog + 1 == gNrbOfLoops && pNbrOfWarnToLog != 0) {
            fprintf(stdout, "%i rows written to the log. No more warnings will be issued from this link.\n", pNbrOfWarnToLog);
        }
        else if (pNbrOfWarnToLog == -1) {
            fprintf(stderr, "%s\n", gLogData.data());
        }

        return (APT_Status) 0;
     }

logic.per_record:
// Convert incoming data from ustring to string

    gInData = UstringToString(Input.AllData);

// Parse the input data

    gErrorCode      = Field(gInData, "||", 1);
    gErrorCode      = Trim(gErrorCode);
    gAdditionalInfo = Field(gInData, "||", 2);
    gAdditionalInfo = Convert(gMapIn, gMapOut, gAdditionalInfo);
    gRCPData        = Fields(gInData, "||", 3, 99999);

// Get the PcsId if possible

    GetPcsId();

// Get the SrcId if possible

    GetSrcId();

// Get the RunId if possible

    GetRunId();

// ... and lose the RCPData if not required

    if ( ! gOutputRCP )
       gRCPData = "";

// Now, get rid of the 'column name' for fields 1-5 (inserted by the peek operator)

    gErrorCode      = Fields(gErrorCode, ':', 2, 99999);
    gAdditionalInfo = Fields(gAdditionalInfo, ':', 2, 99999);
    
// Lookup the error code

    GetErrorKey(gErrorCode);

// and log the error

   gNrbOfLoops = gNrbOfLoops + 1;
   if ( LogIt(gNrbOfLoops, pNbrOfWarnToLog))
         failStep();
